function buscarUsuario() {
  return Promise.resolve({ id: 1, nome: "Ana" });
}

function buscarPedidos(usuario) {
  return Promise.resolve(["Pedido A", "Pedido B"]);
}

buscarUsuario()
  .then(function (usuario) {
    return buscarPedidos(usuario);
  })
  .then(function (pedidos) {
    console.log(pedidos);
  });

